    "voice_pack_words_title": "Höre ein Wort mit deiner Stimme",
    "voice_pack_words_ready": "Tippe auf ein Wort, um es aus DEINEN Lauten gebildet zu hören.",
    "voice_pack_words_hint": "Nimm die Laute eines Wortes auf, dann tippe darauf, um das ganze Wort mit deiner eigenen Stimme zu hören.",
    "voice_pack_word_hear": "{word} mit deiner Stimme hören",
